/**
 * Cloudflare Worker - Yalla Shoot Scraper v3 + PWA
 * =================================================
 * المهام:
 *   - سكرابينغ مباريات yallashoot-id1.xyz (تحديث كل ساعة)
 *   - خدمة أصول PWA (manifest, sw, icons)
 *   - دعم تيليجرام في البيانات
 *
 * نقاط النهاية:
 *   /scrape/all, /scrape/today, /scrape/yesterday, /scrape/tomorrow
 *   /manifest.json, /sw.js
 *   /icon-192.png, /icon-maskable.png
 *   /html/all, /health
 */

// === إعدادات ===
const BASE_URL = 'https://www.yallashoot-id1.xyz';
const CACHE_TTL_SECONDS = 3600; // ساعة - احتراماً للموقع الأصلي

const TELEGRAM_CHANNEL = {
  username: 'gmt_apt',
  url: 'https://t.me/gmt_apt',
  name: 'GMT APT',
  description: 'اشترك لتصلك تنبيهات المباريات والروابط أولاً بأول'
};

const SECTIONS = {
  yesterday: 'matches-yesterday',
  today: 'matches-today',
  tomorrow: 'matches-tomorrow'
};

const STATUS_LABELS = {
  live: 'جارية الآن',
  upcoming: 'لم تبدأ بعد',
  finished: 'انتهت'
};

// === PWA Assets (Base64 Encoded) ===
const ICON_192_B64 = "";
const ICON_MASK_B64 = "";

// === PWA Manifest ===
const MANIFEST = {
  name: "يلا شوت - جدول المباريات",
  short_name: "يلا شوت",
  description: "جدول مباريات كرة القدم مع تحديث تلقائي كل ساعة",
  start_url: "/",
  scope: "/",
  display: "standalone",
  orientation: "portrait",
  lang: "ar",
  dir: "rtl",
  theme_color: "#0f7a3a",
  background_color: "#0e1116",
  categories: ["sports", "news", "entertainment"],
  icons: [
    {
      src: "/icon-192.png",
      sizes: "192x192",
      type: "image/png",
      purpose: "any"
    },
    {
      src: "/icon-maskable.png",
      sizes: "192x192",
      type: "image/png",
      purpose: "maskable"
    },
    {
      src: "/icon-512.png",
      sizes: "512x512",
      type: "image/png",
      purpose: "any"
    }
  ]
};

// === Service Worker Code ===
const SERVICE_WORKER_CODE = `
// Yalla Shoot Service Worker v3
const CACHE_NAME = 'yalla-v3-' + Date.now();
const ESSENTIALS = ['/scrape/all', '/scrape/today'];

self.addEventListener('install', event => {
  self.skipWaiting();
});

self.addEventListener('activate', event => {
  event.waitUntil(self.clients.claim());
});

self.addEventListener('fetch', event => {
  const url = new URL(event.request.url);
  // للطلبات إلى نفس origin (Worker URL)
  if (url.origin === self.location.origin) {
    // استراتيجية: شبكة أولاً، ثم cache كاحتياط
    event.respondWith(
      fetch(event.request)
        .then(response => {
          // تخزين نسخة في الكاش للنجوم
          if (response.ok && (event.request.method === 'GET')) {
            const clone = response.clone();
            caches.open(CACHE_NAME).then(cache => cache.put(event.request, clone));
          }
          return response;
        })
        .catch(() => caches.match(event.request).then(r => r || new Response('Offline', {status: 503})))
    );
  }
});

self.addEventListener('message', event => {
  if (event.data && event.data.type === 'SKIP_WAITING') {
    self.skipWaiting();
  }
});
`;

// === Helper functions ===

function decodeBase64(b64) {
  // Cloudflare Workers: atob() متاح
  const binary = atob(b64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes;
}

function statusFromClass(classes) {
  if (classes.includes('live'))         return 'live';
  if (classes.includes('not-started'))  return 'upcoming';
  if (classes.includes('finished'))     return 'finished';
  if (classes.includes('ft'))           return 'finished';
  return 'unknown';
}

function parseMatches(html, section) {
  const matches = [];
  const matchBlocks = html.match(/<div class="AY_Match[^"]*"[^>]*>[\s\S]*?(?=<div class="AY_Match|$)/g) || [];

  matchBlocks.forEach((block, idx) => {
    const homeMatch = block.match(/<div class="MT_Team TM1"[\s\S]*?<img[^>]*?alt="([^"]*)"[^>]*?data-src="([^"]*)"[\s\S]*?<div class="TM_Name">\s*([^<]+?)\s*<\/div>/);
    const awayMatch = block.match(/<div class="MT_Team TM2"[\s\S]*?<img[^>]*?alt="([^"]*)"[^>]*?data-src="([^"]*)"[\s\S]*?<div class="TM_Name">\s*([^<]+?)\s*<\/div>/);
    if (!homeMatch || !awayMatch) return;

    const timeMatch = block.match(/<span class="MT_Time">\s*([^<]+?)\s*<\/span>/);
    const goals = [...block.matchAll(/<span class="RS-goals">\s*(\d+)\s*<\/span>/g)].map(m => parseInt(m[1]));
    const statMatch = block.match(/<div class="MT_Stat">\s*([^<]+?)\s*<\/div>/);

    const infoMatch = block.match(/<div class="MT_Info">\s*<ul>([\s\S]*?)<\/ul>/);
    let channel = '', commentator = '', competitionFull = '', country = '', competition = '';
    if (infoMatch) {
      const lis = [...infoMatch[1].matchAll(/<li>\s*<span>\s*([^<]+?)\s*<\/span>\s*<\/li>/g)].map(m => m[1].trim());
      channel = lis[0] || '';
      commentator = lis[1] || '';
      competitionFull = lis[2] || '';
      const parts = competitionFull.split(',');
      country = (parts[0] || '').trim();
      competition = (parts.slice(1).join(',') || competitionFull).trim();
    }

    const watchMatch = block.match(/<a href="([^"]+)"[^>]*title="شاهد[^"]*"/);
    const ayMatchClass = (block.match(/<div class="AY_Match\s+([^"]+)"/) || [])[1] || '';
    const status = statusFromClass(ayMatchClass.split(/\s+/));
    const statusLabel = STATUS_LABELS[status] || (statMatch?.[1]?.trim()) || '';

    const homeGoals = goals[0] ?? 0;
    const awayGoals = goals[1] ?? 0;

    matches.push({
      id: section + '-' + (idx + 1),
      section: section,
      home_team: { name: homeMatch[3].trim(), logo: homeMatch[2].trim() },
      away_team: { name: awayMatch[3].trim(), logo: awayMatch[2].trim() },
      time: timeMatch ? timeMatch[1].trim() : '',
      score: { home: homeGoals, away: awayGoals, display: homeGoals + ' - ' + awayGoals },
      status: status,
      status_label: statusLabel,
      channel: channel,
      commentator: commentator,
      country: country,
      competition: competition,
      competition_full: competitionFull,
      watch_url: watchMatch ? watchMatch[1].trim() : ''
    });
  });

  return matches;
}

async function scrapeSection(section) {
  const path = SECTIONS[section];
  if (!path) return [];
  const url = BASE_URL + '/' + path + '/';
  try {
    const response = await fetch(url, {
      headers: {
        'User-Agent': 'Mozilla/5.0 (compatible; CloudflareWorker/3.0; +https://workers.cloudflare.com)',
        'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
        'Accept-Language': 'ar,en;q=0.9'
      }
    });
    if (!response.ok) {
      console.error('Failed: ' + url + ' - ' + response.status);
      return [];
    }
    const html = await response.text();
    return parseMatches(html, section);
  } catch (err) {
    console.error('Error: ' + section + ' - ' + err.message);
    return [];
  }
}

// === Main Router ===

export default {
  async fetch(request, env, ctx) {
    if (request.method === 'OPTIONS') {
      return new Response(null, {
        status: 204,
        headers: {
          'Access-Control-Allow-Origin': '*',
          'Access-Control-Allow-Methods': 'GET, OPTIONS',
          'Access-Control-Allow-Headers': 'Content-Type',
          'Access-Control-Max-Age': '86400'
        }
      });
    }

    const url = new URL(request.url);
    const path = url.pathname;

    // ===== PWA Endpoints =====

    if (path === '/manifest.json' || path === '/manifest.webmanifest') {
      return new Response(JSON.stringify(MANIFEST, null, 2), {
        headers: {
          'Content-Type': 'application/manifest+json',
          'Access-Control-Allow-Origin': '*',
          'Cache-Control': 'public, max-age=86400'
        }
      });
    }

    if (path === '/sw.js') {
      return new Response(SERVICE_WORKER_CODE, {
        headers: {
          'Content-Type': 'application/javascript; charset=utf-8',
          'Access-Control-Allow-Origin': '*',
          'Service-Worker-Allowed': '/',
          'Cache-Control': 'public, max-age=86400'
        }
      });
    }

    if (path === '/icon-192.png') {
      return new Response(decodeBase64(ICON_192_B64), {
        headers: {
          'Content-Type': 'image/png',
          'Cache-Control': 'public, max-age=2592000',
          'Access-Control-Allow-Origin': '*'
        }
      });
    }

    if (path === '/icon-maskable.png' || path === '/icon-maskable-192.png') {
      return new Response(decodeBase64(ICON_MASK_B64), {
        headers: {
          'Content-Type': 'image/png',
          'Cache-Control': 'public, max-age=2592000',
          'Access-Control-Allow-Origin': '*'
        }
      });
    }

    if (path === '/icon-512.png') {
      // إعادة توجيه إلى 192 (لتقليل حجم الـ Worker)
      return Response.redirect(url.origin + '/icon-192.png', 301);
    }

    // ===== Scraping Endpoints =====

    if (path === '/scrape/all' || path === '/') {
      return await handleAllSections(ctx);
    }

    const sectionMatch = path.match(/^\/scrape\/(yesterday|today|tomorrow)\/?$/);
    if (sectionMatch) {
      return await handleSingleSection(sectionMatch[1], ctx);
    }

    if (path === '/html/all') {
      return await handleHtmlEndpoint(ctx);
    }

    if (path === '/health') {
      return jsonResponse({
        status: 'ok',
        version: '3.0',
        timestamp: new Date().toISOString(),
        cache_ttl: CACHE_TTL_SECONDS,
        telegram_channel: TELEGRAM_CHANNEL,
        pwa_endpoints: ['/manifest.json', '/sw.js', '/icon-192.png', '/icon-maskable.png'],
        scrape_endpoints: ['/scrape/all', '/scrape/today', '/scrape/yesterday', '/scrape/tomorrow'],
        html_endpoint: '/html/all'
      });
    }

    return jsonResponse({
      error: 'Not Found',
      usage: {
        scrape: ['/scrape/all', '/scrape/today', '/scrape/yesterday', '/scrape/tomorrow'],
        pwa: ['/manifest.json', '/sw.js', '/icon-192.png', '/icon-maskable.png'],
        html: '/html/all',
        health: '/health'
      }
    }, 404);
  }
};

async function handleSingleSection(section, ctx) {
  const cacheKey = 'section-' + section + '-v3';
  const cache = caches.default;
  const cached = await cache.match(cacheKey);
  if (cached) return cached;

  const matches = await scrapeSection(section);
  const response = jsonResponse({
    source: BASE_URL,
    section: section,
    scraped_at: new Date().toISOString(),
    count: matches.length,
    telegram: TELEGRAM_CHANNEL,
    matches: matches
  });
  ctx.waitUntil(cache.put(cacheKey, response.clone()));
  return response;
}

async function handleAllSections(ctx) {
  const cacheKey = 'all-sections-v3';
  const cache = caches.default;
  const cached = await cache.match(cacheKey);
  if (cached) return cached;

  const [yesterday, today, tomorrow] = await Promise.all([
    scrapeSection('yesterday'),
    scrapeSection('today'),
    scrapeSection('tomorrow')
  ]);

  const allMatches = [...yesterday, ...today, ...tomorrow];

  const data = {
    source: BASE_URL,
    scraped_at: new Date().toISOString(),
    timezone: 'Africa/Cairo',
    version: '3.0',
    telegram: TELEGRAM_CHANNEL,
    matches: { yesterday, today, tomorrow },
    stats: {
      total: allMatches.length,
      by_section: {
        yesterday: yesterday.length,
        today: today.length,
        tomorrow: tomorrow.length
      },
      by_status: {
        live:     allMatches.filter(m => m.status === 'live').length,
        upcoming: allMatches.filter(m => m.status === 'upcoming').length,
        finished: allMatches.filter(m => m.status === 'finished').length
      }
    }
  };

  const response = jsonResponse(data);
  ctx.waitUntil(cache.put(cacheKey, response.clone()));
  return response;
}

async function handleHtmlEndpoint(ctx) {
  const data = await handleAllSections(ctx);
  const json = await data.json();
  const html = renderHtmlPage(json);
  return new Response(html, {
    headers: {
      'Content-Type': 'text/html; charset=utf-8',
      'Access-Control-Allow-Origin': '*',
      'Cache-Control': 'public, max-age=' + CACHE_TTL_SECONDS
    }
  });
}

function renderHtmlPage(json) {
  const tg = json.telegram;
  const all = [...json.matches.today, ...json.matches.yesterday, ...json.matches.tomorrow];
  const cards = [];
  all.forEach((m, idx) => {
    cards.push(renderMatchCard(m));
    if (idx === 2 || idx === 5) cards.push(renderTelegramCard(tg));
  });
  return `<!DOCTYPE html>
<html lang="ar" dir="rtl"><head><meta charset="UTF-8"><title>يلا شوت</title>
<style>body{background:#0e1116;color:#e6e9ef;font-family:Tajawal,sans-serif;direction:rtl;margin:0;padding:12px}
.m{display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:10px}
.c{background:#181c24;border:1px solid #232a37;border-radius:10px;padding:10px}
.empty{text-align:center;padding:30px;color:#888}</style></head><body>
<h1 style="text-align:center;color:#fff">⚽ جدول المباريات (${json.stats.total} مباراة)</h1>
<div class="m">${cards.length ? cards.join('') : '<div class="empty">لا توجد مباريات</div>'}</div>
</body></html>`;
}

function renderMatchCard(m) {
  return '<div class="c"><strong>' + escapeHtml(m.home_team.name) + '</strong> vs <strong>' + escapeHtml(m.away_team.name) + '</strong><br>' + escapeHtml(m.score.display) + ' · ' + escapeHtml(m.status_label) + '</div>';
}

function renderTelegramCard(tg) {
  return '<div class="c" style="background:#229ED9;color:#fff;text-align:center"><h3>اشترك في ' + escapeHtml(tg.username) + '</h3><a href="' + escapeHtml(tg.url) + '" style="color:#fff">@' + escapeHtml(tg.username) + '</a></div>';
}

function escapeHtml(s) {
  if (s == null) return '';
  return String(s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
}

function jsonResponse(data, status) {
  if (status === undefined) status = 200;
  return new Response(JSON.stringify(data, null, 2), {
    status: status,
    headers: {
      'Content-Type': 'application/json; charset=utf-8',
      'Access-Control-Allow-Origin': '*',
      'Cache-Control': 'public, max-age=' + CACHE_TTL_SECONDS
    }
  });
}
